// client/src/components/Admin/NotificationPanel.tsx

import { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    Bell, UserPlus, Mail, Award, AlertTriangle,
    ShieldAlert, Settings, Trash2, CheckCheck, X, Loader2
} from 'lucide-react';
import api from '../../utils/api';
import type { INotification, NotificationCategory } from '../../types/notification';

// ΓöÇΓöÇ Category config ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const CATEGORY_CONFIG: Record<NotificationCategory, {
    label: string;
    dot: string;
    bg: string;
    text: string;
    border: string;
}> = {
    business: {
        label: 'Business',
        dot: 'bg-emerald-500',
        bg: 'bg-emerald-50 dark:bg-emerald-900/20',
        text: 'text-emerald-600 dark:text-emerald-400',
        border: 'border-emerald-200 dark:border-emerald-800',
    },
    academic: {
        label: 'Academic',
        dot: 'bg-amber-500',
        bg: 'bg-amber-50 dark:bg-amber-900/20',
        text: 'text-amber-600 dark:text-amber-400',
        border: 'border-amber-200 dark:border-amber-800',
    },
    security: {
        label: 'Security',
        dot: 'bg-rose-500',
        bg: 'bg-rose-50 dark:bg-rose-900/20',
        text: 'text-rose-600 dark:text-rose-400',
        border: 'border-rose-200 dark:border-rose-800',
    },
};

// ΓöÇΓöÇ Icon by title keyword ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const getIcon = (title: string, category: NotificationCategory) => {
    const t = title.toLowerCase();
    if (t.includes('enrollment')) return <UserPlus size={15} />;
    if (t.includes('inquiry') || t.includes('message')) return <Mail size={15} />;
    if (t.includes('certificate')) return <Award size={15} />;
    if (t.includes('seat')) return <AlertTriangle size={15} />;
    if (t.includes('admin')) return <Settings size={15} />;
    if (t.includes('login') || t.includes('failed')) return <ShieldAlert size={15} />;
    if (category === 'security') return <ShieldAlert size={15} />;
    if (category === 'academic') return <Award size={15} />;
    return <Bell size={15} />;
};

// ΓöÇΓöÇ Time formatter ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const timeAgo = (dateStr: string) => {
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return `${mins}m ago`;
    if (hours < 24) return `${hours}h ago`;
    return `${days}d ago`;
};

// ΓöÇΓöÇ Tab type ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
type Tab = 'all' | NotificationCategory;

// ΓöÇΓöÇ Main Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const NotificationPanel = () => {
    const [open, setOpen] = useState(false);
    const [notifications, setNotifications] = useState<INotification[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const [activeTab, setActiveTab] = useState<Tab>('all');
    const [loading, setLoading] = useState(false);
    const [marking, setMarking] = useState(false);
    const panelRef = useRef<HTMLDivElement>(null);
    const navigate = useNavigate();

    // ΓöÇΓöÇ Fetch ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const fetchNotifications = async () => {
        setLoading(true);
        try {
            const res = await api.get('/admin/notifications');
            setNotifications(res.data.notifications);
            setUnreadCount(res.data.unreadCount);
        } catch (err) {
            console.error('Failed to fetch notifications');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchNotifications();
        // Poll every 60 seconds for new notifications
        const interval = setInterval(fetchNotifications, 60000);
        return () => clearInterval(interval);
    }, []);

    // ΓöÇΓöÇ Close on outside click ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    useEffect(() => {
        const handler = (e: MouseEvent) => {
            if (panelRef.current && !panelRef.current.contains(e.target as Node)) {
                setOpen(false);
            }
        };
        document.addEventListener('mousedown', handler);
        return () => document.removeEventListener('mousedown', handler);
    }, []);

    // ΓöÇΓöÇ Mark single as read + navigate ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const handleClick = async (n: INotification) => {
        if (!n.isRead) {
            await api.patch(`/admin/notifications/${n._id}/read`);
            setNotifications(prev =>
                prev.map(x => x._id === n._id ? { ...x, isRead: true } : x)
            );
            setUnreadCount(prev => Math.max(0, prev - 1));
        }
        setOpen(false);
        navigate(n.link);
    };

    // ΓöÇΓöÇ Mark all as read ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const handleMarkAllRead = async () => {
        setMarking(true);
        try {
            await api.patch('/admin/notifications/read-all');
            setNotifications(prev => prev.map(x => ({ ...x, isRead: true })));
            setUnreadCount(0);
        } finally {
            setMarking(false);
        }
    };

    // ΓöÇΓöÇ Delete ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const handleDelete = async (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        await api.delete(`/admin/notifications/${id}`);
        const deleted = notifications.find(n => n._id === id);
        setNotifications(prev => prev.filter(n => n._id !== id));
        if (deleted && !deleted.isRead) setUnreadCount(prev => Math.max(0, prev - 1));
    };

    // ΓöÇΓöÇ Filtered list ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const filtered = activeTab === 'all'
        ? notifications
        : notifications.filter(n => n.category === activeTab);

    const TABS: { key: Tab; label: string; dot?: string }[] = [
        { key: 'all', label: 'All' },
        { key: 'business', label: 'Business', dot: 'bg-emerald-500' },
        { key: 'academic', label: 'Academic', dot: 'bg-amber-500' },
        { key: 'security', label: 'Security', dot: 'bg-rose-500' },
    ];

    return (
        <div ref={panelRef} className="relative">

            {/* ΓöÇΓöÇ Bell Button ΓöÇΓöÇ */}
            <button
                onClick={() => setOpen(prev => !prev)}
                className="relative p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
            >
                <Bell size={20} />
                {unreadCount > 0 && (
                    <span className="absolute -top-1 -right-1 min-w-[18px] h-[18px] bg-rose-500 text-white text-[9px] font-black rounded-full flex items-center justify-center px-1 border-2 border-white dark:border-slate-900">
                        {unreadCount > 99 ? '99+' : unreadCount}
                    </span>
                )}
            </button>

            {/* ΓöÇΓöÇ Panel ΓöÇΓöÇ */}
            {open && (
                <div className="absolute right-0 top-14 w-[380px] bg-white dark:bg-slate-900 rounded-[1.75rem] border border-slate-200 dark:border-slate-700 shadow-2xl shadow-slate-200/60 dark:shadow-slate-900/60 overflow-hidden z-50"
                    style={{ animation: 'dropIn 0.2s cubic-bezier(0.23,1,0.32,1) both' }}
                >
                    <style>{`
            @keyframes dropIn {
              from { opacity: 0; transform: translateY(-8px) scale(0.97); }
              to   { opacity: 1; transform: translateY(0) scale(1); }
            }
          `}</style>

                    {/* Header */}
                    <div className="px-5 pt-5 pb-3 border-b border-slate-100 dark:border-slate-800">
                        <div className="flex items-center justify-between mb-3">
                            <div>
                                <h3 className="font-black text-slate-900 dark:text-white text-sm uppercase tracking-tight">
                                    Notifications
                                </h3>
                                <p className="text-[10px] text-slate-400 font-medium mt-0.5">
                                    {unreadCount > 0 ? `${unreadCount} unread` : 'All caught up!'}
                                </p>
                            </div>
                            <div className="flex items-center gap-2">
                                {unreadCount > 0 && (
                                    <button
                                        onClick={handleMarkAllRead}
                                        disabled={marking}
                                        className="flex items-center gap-1.5 text-[10px] font-black text-indigo-600 uppercase tracking-widest hover:text-indigo-800 transition-colors disabled:opacity-50"
                                    >
                                        {marking
                                            ? <Loader2 size={11} className="animate-spin" />
                                            : <CheckCheck size={11} />
                                        }
                                        Mark all read
                                    </button>
                                )}
                                <button
                                    onClick={() => setOpen(false)}
                                    className="p-1 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors"
                                >
                                    <X size={14} />
                                </button>
                            </div>
                        </div>

                        {/* Tabs */}
                        <div className="flex gap-1">
                            {TABS.map(tab => (
                                <button
                                    key={tab.key}
                                    onClick={() => setActiveTab(tab.key)}
                                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all ${activeTab === tab.key
                                            ? 'bg-indigo-600 text-white shadow-sm'
                                            : 'text-slate-400 hover:text-slate-600 hover:bg-slate-100 dark:hover:bg-slate-800'
                                        }`}
                                >
                                    {tab.dot && <span className={`w-1.5 h-1.5 rounded-full ${tab.dot}`} />}
                                    {tab.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* List */}
                    <div className="overflow-y-auto max-h-[380px]">
                        {loading ? (
                            <div className="flex items-center justify-center py-12">
                                <Loader2 className="animate-spin text-indigo-600 w-6 h-6" />
                            </div>
                        ) : filtered.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-12 gap-3">
                                <div className="w-12 h-12 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-300">
                                    <Bell size={22} />
                                </div>
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">No notifications</p>
                            </div>
                        ) : (
                            <div className="p-2 space-y-1">
                                {filtered.map(n => {
                                    const cfg = CATEGORY_CONFIG[n.category];
                                    return (
                                        <div
                                            key={n._id}
                                            onClick={() => handleClick(n)}
                                            className={`group relative flex items-start gap-3 p-3.5 rounded-2xl cursor-pointer transition-all hover:bg-slate-50 dark:hover:bg-slate-800/60 ${!n.isRead ? 'bg-slate-50/80 dark:bg-slate-800/40' : ''
                                                }`}
                                        >
                                            {/* Unread dot */}
                                            {!n.isRead && (
                                                <span className="absolute top-4 left-2 w-1.5 h-1.5 rounded-full bg-indigo-500" />
                                            )}

                                            {/* Icon */}
                                            <div className={`shrink-0 w-9 h-9 rounded-xl flex items-center justify-center border ${cfg.bg} ${cfg.text} ${cfg.border}`}>
                                                {getIcon(n.title, n.category)}
                                            </div>

                                            {/* Content */}
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-start justify-between gap-2">
                                                    <p className={`text-xs font-black truncate ${!n.isRead ? 'text-slate-900 dark:text-white' : 'text-slate-600 dark:text-slate-400'}`}>
                                                        {n.title}
                                                    </p>
                                                    <span className={`shrink-0 text-[9px] font-black uppercase px-2 py-0.5 rounded-full border ${cfg.bg} ${cfg.text} ${cfg.border}`}>
                                                        {cfg.label}
                                                    </span>
                                                </div>
                                                <p className="text-[11px] text-slate-500 dark:text-slate-400 mt-0.5 leading-snug line-clamp-2">
                                                    {n.message}
                                                </p>
                                                <p className="text-[10px] text-slate-400 mt-1 font-medium">
                                                    {timeAgo(n.createdAt)}
                                                </p>
                                            </div>

                                            {/* Delete */}
                                            <button
                                                onClick={e => handleDelete(e, n._id)}
                                                className="shrink-0 opacity-0 group-hover:opacity-100 p-1 rounded-lg hover:bg-rose-100 dark:hover:bg-rose-900/30 text-slate-300 hover:text-rose-500 transition-all"
                                            >
                                                <Trash2 size={12} />
                                            </button>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>

                    {/* Footer */}
                    {notifications.length > 0 && (
                        <div className="px-5 py-3 border-t border-slate-100 dark:border-slate-800">
                            <button
                                onClick={() => { setOpen(false); navigate('/admin/notifications'); }}
                                className="w-full text-center text-[10px] font-black text-indigo-600 uppercase tracking-widest hover:text-indigo-800 transition-colors"
                            >
                                View all notifications ΓåÆ
                            </button>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default NotificationPanel;

// client/src/components/Admin/TopHeader.tsx

import { Search, Moon, Sun, ChevronDown } from 'lucide-react';
import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import NotificationPanel from './NotificationPanel';

const TopHeader = () => {
  const [isDark, setIsDark] = useState(
    document.documentElement.classList.contains('dark')
  );
  const [searchVal, setSearchVal] = useState('');
  const [profileOpen, setProfileOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);
  const navigate   = useNavigate();

  // ΓöÇΓöÇ Theme toggle ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const toggleTheme = () => {
    if (document.documentElement.classList.contains('dark')) {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
      setIsDark(true);
    }
  };

  useEffect(() => {
    setIsDark(document.documentElement.classList.contains('dark'));
  }, []);

  // ΓöÇΓöÇ Close profile dropdown on outside click ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(e.target as Node)) {
        setProfileOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  // ΓöÇΓöÇ Search submit ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchVal.trim()) navigate(`/search?q=${encodeURIComponent(searchVal.trim())}`);
  };

  // ΓöÇΓöÇ Read admin info from localStorage ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const storedUser = localStorage.getItem('skillsandscale_user');
  const adminName  = storedUser ? JSON.parse(storedUser)?.name ?? 'Admin' : 'Admin';
  const adminRole  = storedUser ? JSON.parse(storedUser)?.role ?? ''      : '';

  const handleLogout = () => {
    localStorage.removeItem('skillsandscale_user');
    navigate('/admin/login');
  };

  return (
    <header className="h-20 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-40 px-8 flex items-center justify-between gap-6 transition-colors">

      {/* ΓöÇΓöÇ Search ΓöÇΓöÇ */}
      <form
        onSubmit={handleSearch}
        className="flex items-center gap-3 bg-slate-100 dark:bg-slate-800 px-4 py-2.5 rounded-2xl w-full max-w-md border border-slate-200 dark:border-slate-700 focus-within:border-indigo-400 dark:focus-within:border-indigo-500 transition-colors"
      >
        <Search size={16} className="text-slate-400 shrink-0" />
        <input
          type="text"
          value={searchVal}
          onChange={e => setSearchVal(e.target.value)}
          placeholder="Search students, courses..."
          className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder:text-slate-400 font-medium"
        />
      </form>

      {/* ΓöÇΓöÇ Right controls ΓöÇΓöÇ */}
      <div className="flex items-center gap-3 shrink-0">

        {/* Theme toggle */}
        <button
          onClick={toggleTheme}
          className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
          title={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
        >
          {isDark ? <Sun size={18} /> : <Moon size={18} />}
        </button>

        {/* Notifications */}
        <NotificationPanel />

        {/* Profile dropdown */}
        <div ref={profileRef} className="relative">
          <button
            onClick={() => setProfileOpen(prev => !prev)}
            className="flex items-center gap-2.5 pl-3 pr-2 py-1.5 rounded-2xl hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
          >
            <div className="text-right hidden md:block">
              <p className="text-xs font-black text-slate-800 dark:text-white leading-tight">{adminName}</p>
              {adminRole && (
                <p className="text-[9px] font-bold text-indigo-500 uppercase tracking-widest leading-tight">{adminRole}</p>
              )}
            </div>
            <img
              src={`https://ui-avatars.com/api/?name=${encodeURIComponent(adminName)}&background=6366f1&color=fff&bold=true`}
              className="w-9 h-9 rounded-xl border-2 border-indigo-200 dark:border-indigo-800"
              alt="Profile"
            />
            <ChevronDown
              size={14}
              className={`text-slate-400 transition-transform ${profileOpen ? 'rotate-180' : ''}`}
            />
          </button>

          {/* Dropdown */}
          {profileOpen && (
            <div
              className="absolute right-0 top-14 w-52 bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-xl overflow-hidden z-50"
              style={{ animation: 'dropIn 0.15s cubic-bezier(0.23,1,0.32,1) both' }}
            >
              <style>{`
                @keyframes dropIn {
                  from { opacity: 0; transform: translateY(-6px) scale(0.97); }
                  to   { opacity: 1; transform: translateY(0) scale(1); }
                }
              `}</style>

              {/* User info */}
              <div className="px-4 py-3 border-b border-slate-100 dark:border-slate-800">
                <p className="text-xs font-black text-slate-900 dark:text-white">{adminName}</p>
                <p className="text-[10px] text-slate-400 font-medium capitalize">{adminRole}</p>
              </div>

              {/* Menu items */}
              <div className="p-1.5">
                {[
                  { label: 'My Profile',   path: '/admin/settings' },
                  { label: 'Settings',     path: '/admin/settings' },
                ].map(item => (
                  <button
                    key={item.label}
                    onClick={() => { setProfileOpen(false); navigate(item.path); }}
                    className="w-full text-left px-3 py-2 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-indigo-600 transition-colors"
                  >
                    {item.label}
                  </button>
                ))}
              </div>

              {/* Logout */}
              <div className="p-1.5 border-t border-slate-100 dark:border-slate-800">
                <button
                  onClick={handleLogout}
                  className="w-full text-left px-3 py-2 rounded-xl text-xs font-bold text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 transition-colors"
                >
                  Sign Out
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </header>
  );
};

export default TopHeader;

import { useState } from 'react';
import { X, Upload, Loader2, CheckCircle, CreditCard } from 'lucide-react';
import api from '../utils/api';

interface BookingModalProps {
  isOpen: boolean;
  onClose: () => void;
  course: any;
}

const MOBILE_NUMBERS: Record<string, string> = {
  Bkash: '015750 78261 (Merchant)',
  Nagad: '015750 78261 (Merchant)',
};

const BookingModal = ({ isOpen, onClose, course }: BookingModalProps) => {
  const [step, setStep]       = useState(1);
  const [loading, setLoading] = useState(false);
  const [file, setFile]       = useState<File | null>(null);
  const [error, setError]     = useState('');

  const [formData, setFormData] = useState({
    fullName:      '',
    email:         '',
    phone:         '',
    address:       '',
    batchNumber:   course?.nextBatch || 'Batch-01',
    transactionId: '',
    paymentMethod: 'Bkash',
  });

  if (!isOpen || !course) return null;

  const isOnline = formData.paymentMethod === 'SSLCommerz';

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError('');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) setFile(e.target.files[0]);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      // ΓöÇΓöÇ Online payment via SSLCommerz ΓöÇΓöÇ
      if (isOnline) {
        const res = await api.post('/payment/init', {
          courseId: course._id,
          personalInfo: {
            fullName: formData.fullName,
            email:    formData.email,
            phone:    formData.phone,
            address:  formData.address,
          },
          courseInfo: { batchNumber: formData.batchNumber },
        });
        window.location.replace(res.data.url);
        return;
      }

      // ΓöÇΓöÇ Manual payment (Bkash / Nagad) ΓöÇΓöÇ
      if (!file) {
        setError('Please upload your payment screenshot.');
        setLoading(false);
        return;
      }

      const data = new FormData();
      data.append('courseId',      course._id);
      data.append('receipt',       file);
      data.append('fullName',      formData.fullName);
      data.append('email',         formData.email);
      data.append('phone',         formData.phone);
      data.append('address',       formData.address);
      data.append('batchNumber',   formData.batchNumber);
      data.append('transactionId', formData.transactionId);
      data.append('paymentMethod', formData.paymentMethod);

      await api.post('/courses/book', data, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });

      setStep(2);

    } catch (err: any) {
      setError(err?.response?.data?.message || 'Booking failed. Please try again.');
    } finally {
      if (!isOnline) setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-[2rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden">

        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 dark:border-slate-800">
          <div>
            <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600">
              {step === 1 ? 'Enrollment' : 'Confirmed'}
            </p>
            <h2 className="text-lg font-black text-slate-900 dark:text-white">
              {step === 1 ? 'Secure Your Seat' : 'Booking Received'}
            </h2>
          </div>
          <button
            onClick={onClose}
            className="p-2 rounded-xl bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
          >
            <X size={18} className="text-slate-500" />
          </button>
        </div>

        <div className="p-6 max-h-[80vh] overflow-y-auto">

          {step === 1 ? (
            <form onSubmit={handleSubmit} className="space-y-4">

              {/* Course info */}
              <div className="flex items-center gap-4 bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-2xl border border-indigo-100 dark:border-indigo-800/30">
                <img src={course.image} alt={course.title} className="w-14 h-14 rounded-xl object-cover shrink-0" />
                <div>
                  <p className="text-xs font-black text-slate-800 dark:text-white">{course.title}</p>
                  <p className="text-indigo-600 font-black text-xl">{course.price}</p>
                </div>
              </div>

              {/* Personal info */}
              <div className="grid grid-cols-2 gap-3">
                {[
                  { label: 'Full Name',  name: 'fullName', placeholder: 'John Doe',        type: 'text'  },
                  { label: 'Phone',      name: 'phone',    placeholder: '017...',           type: 'tel'   },
                ].map(f => (
                  <div key={f.name}>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{f.label}</label>
                    <input
                      required name={f.name} type={f.type}
                      onChange={handleChange} placeholder={f.placeholder}
                      className="w-full px-4 py-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none dark:text-white text-sm font-semibold"
                    />
                  </div>
                ))}
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Email</label>
                <input
                  required name="email" type="email"
                  onChange={handleChange} placeholder="you@example.com"
                  className="w-full px-4 py-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none dark:text-white text-sm font-semibold"
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Address</label>
                <input
                  required name="address"
                  onChange={handleChange} placeholder="Full address"
                  className="w-full px-4 py-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none dark:text-white text-sm font-semibold"
                />
              </div>

              {/* Payment */}
              <div className="border-t border-slate-100 dark:border-slate-800 pt-4">
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-3">Payment Method</p>

                <select
                  name="paymentMethod"
                  onChange={handleChange}
                  value={formData.paymentMethod}
                  className="w-full px-4 py-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none dark:text-white text-sm font-bold cursor-pointer mb-3"
                >
                  <option value="Bkash">Bkash (Personal / Merchant)</option>
                  <option value="Nagad">Nagad (Personal / Merchant)</option>
                  <option value="SSLCommerz">Pay Online (SSLCommerz)</option>
                </select>

                {/* Manual payment instructions */}
                {!isOnline && (
                  <>
                    <div className="bg-amber-50 dark:bg-amber-900/10 border border-amber-200 dark:border-amber-800/30 rounded-xl p-4 mb-3 flex gap-3">
                      <CreditCard size={18} className="text-amber-500 shrink-0 mt-0.5" />
                      <div className="text-xs text-amber-800 dark:text-amber-200">
                        <p className="font-black mb-1">Instructions</p>
                        <p>1. Send <strong>{course.price}</strong> to{' '}
                          <span className="font-mono bg-white dark:bg-black px-1.5 py-0.5 rounded text-indigo-600 dark:text-indigo-400 font-bold">
                            {MOBILE_NUMBERS[formData.paymentMethod]}
                          </span>
                        </p>
                        <p className="mt-0.5">2. Enter your TrxID below and upload the screenshot.</p>
                      </div>
                    </div>

                    <div className="space-y-3">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Transaction ID</label>
                        <input
                          required name="transactionId"
                          onChange={handleChange} placeholder="TRX..."
                          className="w-full px-4 py-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none dark:text-white text-sm font-bold uppercase tracking-widest"
                        />
                      </div>

                      <div className="relative border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-xl p-5 text-center hover:border-indigo-400 transition-colors cursor-pointer group">
                        <input
                          type="file" accept="image/*"
                          onChange={handleFileChange}
                          className="absolute inset-0 opacity-0 cursor-pointer"
                        />
                        <div className="flex flex-col items-center gap-2 text-slate-400 group-hover:text-indigo-500 transition-colors">
                          {file
                            ? <CheckCircle className="text-emerald-500" size={28} />
                            : <Upload size={22} />
                          }
                          <span className="text-[11px] font-black uppercase tracking-widest">
                            {file ? file.name : 'Upload Payment Screenshot'}
                          </span>
                        </div>
                      </div>
                    </div>
                  </>
                )}
              </div>

              {/* Error */}
              {error && (
                <p className="text-xs font-bold text-rose-500 bg-rose-50 dark:bg-rose-900/20 px-4 py-2.5 rounded-xl">
                  {error}
                </p>
              )}

              <button
                type="submit"
                disabled={loading}
                className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:opacity-60 disabled:cursor-not-allowed text-white py-3.5 rounded-xl font-black text-sm uppercase tracking-widest flex items-center justify-center gap-2 transition-colors shadow-lg shadow-indigo-500/20"
              >
                {loading
                  ? <><Loader2 size={16} className="animate-spin" /> ProcessingΓÇª</>
                  : isOnline ? 'Pay Now Securely' : 'Confirm Booking'
                }
              </button>
            </form>

          ) : (
            // ΓöÇΓöÇ Success state (manual only) ΓöÇΓöÇ
            <div className="text-center py-8">
              <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mx-auto mb-5">
                <CheckCircle size={40} className="text-emerald-500" />
              </div>
              <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">Booking Received!</h3>
              <p className="text-slate-500 text-sm max-w-xs mx-auto mb-6 leading-relaxed">
                Your payment details have been submitted. We'll verify and send a confirmation email shortly.
              </p>
              <button
                onClick={onClose}
                className="bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest hover:opacity-90 transition-opacity"
              >
                Close
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BookingModal;

