                </div>
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={data.trafficChart} margin={{ top: 5, right: 5, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" vertical={false} />
                    <XAxis dataKey="day" tick={{ fontSize: 10, fontWeight: 700, fill: '#94a3b8' }} axisLine={false} tickLine={false} />
                    <YAxis tick={{ fontSize: 10, fontWeight: 700, fill: '#94a3b8' }} axisLine={false} tickLine={false} />
                    <Tooltip content={<CustomTooltip />} />
                    <Bar dataKey="enrollments" name="Enrollments" fill="#6366f1" radius={[6, 6, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </>
            )}
          </div>

          {/* Enrollment Mix Pie */}
          <div
            className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 p-6 shadow-sm"
            style={{ animation: 'fadeSlideUp 0.5s 0.3s ease both' }}
          >
            <SectionHeader icon={<BookOpen size={16} />} title="Enrollment Mix" />
            {data.enrollmentMix.length === 0 ? (
              <div className="flex items-center justify-center h-40 text-slate-400 text-xs font-bold">No data yet</div>
            ) : (
              <>
                <div className="flex justify-center my-2">
                  <ResponsiveContainer width={180} height={180}>
                    <PieChart>
                      <Pie data={data.enrollmentMix} cx="50%" cy="50%" innerRadius={52} outerRadius={80} paddingAngle={3} dataKey="value">
                        {data.enrollmentMix.map((entry, i) => (
                          <Cell key={i} fill={entry.color} />
                        ))}
                      </Pie>
                      <Tooltip
                        formatter={(v: any) => `${v}%`}
                        contentStyle={{ borderRadius: 12, fontSize: 11, border: 'none', boxShadow: '0 4px 20px rgba(0,0,0,0.15)' }}
                      />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
                <div className="space-y-2.5 mt-2">
                  {data.enrollmentMix.map(item => (
                    <div key={item.name} className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <span className="w-2.5 h-2.5 rounded-full shrink-0" style={{ background: item.color }} />
                        <span className="text-[11px] font-bold text-slate-600 dark:text-slate-400">{item.name}</span>
                      </div>
                      <span className="text-[11px] font-black text-slate-800 dark:text-white">{item.value}%</span>
                    </div>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>

        {/* ΓöÇΓöÇ Bottom Row ΓöÇΓöÇ */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

          {/* Recent Enrollments */}
          <div
            className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 p-6 shadow-sm"
            style={{ animation: 'fadeSlideUp 0.5s 0.4s ease both' }}
          >
            <SectionHeader icon={<Users size={16} />} title="Recent Enrollments" action="View All" />
            {data.recentEnrollments.length === 0 ? (
              <div className="flex items-center justify-center h-32 text-slate-400 text-xs font-bold">No enrollments yet</div>
            ) : (
              <div className="space-y-2">
                {data.recentEnrollments.map((enr, i) => (
                  <div key={i} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                    <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white text-[10px] font-black shrink-0 shadow-md">
                      {enr.avatar}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-black text-slate-800 dark:text-white truncate">{enr.name}</p>
                      <p className="text-[10px] text-slate-400 font-medium truncate">{enr.course}</p>
                    </div>
                    <div className="text-right shrink-0">
                      <p className="text-xs font-black text-slate-800 dark:text-white">{enr.amount}</p>
                      <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full ${enr.status === 'ongoing' ? 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400' :
                        enr.status === 'completed' ? 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400' :
                          enr.status === 'pending' ? 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400' :
                            'bg-rose-100 text-rose-600 dark:bg-rose-900/30 dark:text-rose-400'
                        }`}>
                        {enr.status}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Top Courses */}
          <div
            className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 p-6 shadow-sm"
            style={{ animation: 'fadeSlideUp 0.5s 0.5s ease both' }}
          >
            <SectionHeader icon={<TrendingUp size={16} />} title="Top Courses" action="View All" />
            {data.topCourses.length === 0 ? (
              <div className="flex items-center justify-center h-32 text-slate-400 text-xs font-bold">No course data yet</div>
            ) : (
              <div className="space-y-2">
                {data.topCourses.map((course, i) => (
                  <div key={i} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                    <div className={`w-7 h-7 rounded-xl flex items-center justify-center text-[10px] font-black shrink-0 ${i === 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'
                      }`}>
                      #{i + 1}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-black text-slate-800 dark:text-white truncate">{course.title}</p>
                      <p className="text-[10px] text-slate-400 font-medium flex items-center gap-1">
                        <Users size={9} /> {course.students} students
                      </p>
                    </div>
                    <div className="text-right shrink-0 space-y-0.5">
                      <p className="text-xs font-black text-emerald-600">{course.revenue}</p>
                      <p className="text-[10px] font-bold text-amber-500 flex items-center justify-end gap-0.5">
                        <Star size={9} fill="currentColor" /> {course.rating}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  );
};

export default Dashboard;

import { useState, useEffect, useRef } from 'react';
import { Upload, Save, Loader2, LayoutGrid, X, Image as ImageIcon, Plus } from 'lucide-react';
import api from '../../utils/api';

interface Project {
  _id: string;
  title: string;
  category: string;
  image: string;
  position: number;
}

const ProjectManager = () => {
  // We manage 6 fixed slots for a perfect Bento Grid
  const SLOTS = [1, 2, 3, 4, 5, 6];

  const [projects, setProjects] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);

  // Editor State
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [selectedSlot, setSelectedSlot] = useState<number | null>(null);
  const [formData, setFormData] = useState({ title: '', category: '' });
  const [preview, setPreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const fetchProjects = async () => {
    try {
      const res = await api.get('/projects');
      setProjects(res.data);
    } catch (err) {
      console.error("Sync Failed");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchProjects(); }, []);

  // Open the modal for a specific slot
  const handleSlotClick = (position: number) => {
    const existing = projects.find(p => p.position === position);
    setSelectedSlot(position);
    setFormData({
      title: existing?.title || '',
      category: existing?.category || ''
    });
    setPreview(existing?.image || null);
    setIsEditorOpen(true);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Create local preview immediately
      setPreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlot) return;

    setUploading(true);
    const data = new FormData();

    // 1. Append Text Data
    data.append('position', selectedSlot.toString());
    data.append('title', formData.title);
    data.append('category', formData.category);

    // 2. Append Image (Only if selected from file input)
    if (fileInputRef.current?.files?.[0]) {
      data.append('image', fileInputRef.current.files[0]);
    } else if (!preview) {
      alert("Image is required for the portfolio.");
      setUploading(false);
      return;
    }

    try {
      // Calls your updateProjectSlot controller
      await api.post('/projects', data, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      await fetchProjects();
      setIsEditorOpen(false);
    } catch (err: any) {
      alert(err.response?.data?.message || "Upload Failed");
    } finally {
      setUploading(false);
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center dark:bg-slate-950"><Loader2 className="animate-spin text-indigo-600" size={40} /></div>;

  return (
    <div className="p-4 md:p-8 animate-in fade-in duration-500">

      <div className="flex justify-between items-end mb-10">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Bento Grid</h1>
          <p className="text-slate-500 font-bold uppercase text-[10px] tracking-[0.4em] mt-1">Portfolio Manager</p>
        </div>
        <div className="bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
          <LayoutGrid size={16} /> 6 Active Slots
        </div>
      </div>

      {/* THE GRID */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {SLOTS.map((slot) => {
          const project = projects.find(p => p.position === slot);

          return (
            <div
              key={slot}
              onClick={() => handleSlotClick(slot)}
              className="group relative h-72 bg-white dark:bg-slate-900 rounded-[2rem] border-2 border-dashed border-slate-200 dark:border-slate-800 hover:border-indigo-500 dark:hover:border-indigo-500 transition-all cursor-pointer overflow-hidden shadow-sm hover:shadow-2xl"
            >
              {project ? (
                <>
                  <img src={project.image} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" alt="Portfolio" />

                  {/* Overlay Gradient */}
                  <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent opacity-60 group-hover:opacity-90 transition-opacity" />

                  <div className="absolute bottom-0 left-0 p-6 w-full translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
                    <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest mb-1">{project.category}</p>
                    <h3 className="text-white font-bold text-xl leading-tight">{project.title}</h3>
                  </div>

                  <div className="absolute top-4 right-4 bg-white/20 text-white w-8 h-8 flex items-center justify-center rounded-full font-black text-xs backdrop-blur-md border border-white/30">
                    {slot}
                  </div>
                </>
              ) : (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 group-hover:text-indigo-500 transition-colors">
                  <div className="p-4 rounded-full bg-slate-50 dark:bg-slate-800 group-hover:bg-indigo-50 dark:group-hover:bg-indigo-900/30 transition-colors">
                    <Plus size={32} />
                  </div>
                  <p className="text-[10px] font-black uppercase tracking-widest mt-4">Empty Slot {slot}</p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* EDITOR MODAL */}
      {isEditorOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md" onClick={() => setIsEditorOpen(false)}></div>

          <div className="relative w-full max-w-lg bg-white dark:bg-slate-900 rounded-[3rem] shadow-2xl overflow-hidden border border-slate-200 dark:border-slate-800 animate-in zoom-in-95 duration-200">

            <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white/50 dark:bg-slate-900/50 backdrop-blur-md">
              <div>
                <h2 className="text-2xl font-bold dark:text-white">Slot 0{selectedSlot}</h2>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Portfolio Metadata</p>
              </div>
              <button onClick={() => setIsEditorOpen(false)} className="p-3 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-red-500 transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              {/* Image Preview / Upload */}
              <div
                onClick={() => fileInputRef.current?.click()}
                className="w-full h-56 bg-slate-100 dark:bg-slate-800 rounded-3xl border-4 border-dashed border-slate-200 dark:border-slate-700 flex flex-col items-center justify-center cursor-pointer overflow-hidden group hover:border-indigo-500 transition-all relative"
              >
                {preview ? (
                  <>
                    <img src={preview} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-sm">
                      <p className="text-white font-bold text-xs uppercase flex items-center gap-2"><ImageIcon size={16} /> Change Cover</p>
                    </div>
                  </>
                ) : (
                  <div className="text-center text-slate-400 group-hover:text-indigo-500">
                    <Upload className="mx-auto mb-3 w-10 h-10" />
                    <p className="text-[9px] font-black uppercase tracking-widest">Click to Upload</p>
                  </div>
                )}
                <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*" />
              </div>

              {/* Inputs */}
              <div className="space-y-4">
                <div>
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-2 mb-1 block">Project Title</label>
                  <input type="text" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-950 border-none outline-none dark:text-white font-bold text-sm" placeholder="e.g. Fintech App" />
                </div>
                <div>
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-2 mb-1 block">Category</label>
                  <input type="text" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-950 border-none outline-none dark:text-white font-bold text-sm" placeholder="e.g. UI/UX Design" />
                </div>
              </div>

              <button type="submit" disabled={uploading} className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 disabled:opacity-50">
                {uploading ? <Loader2 className="animate-spin" /> : <Save size={18} />} {uploading ? 'Processing...' : 'Save to Slot'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProjectManager;

import { useState, useEffect } from 'react';
import { Edit, Trash2, X, Save, Loader2, Palette, Megaphone } from 'lucide-react';
import ConfirmModal from '../../Components/Admin/ConfirmModal';
import { IconMap, AvailableIcons } from '../../utils/IconRegistry';
import api from '../../utils/api';

const ServiceManager = () => {
  const [services, setServices] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formData, setFormData] = useState({ title: '', category: 'Design', icon: 'PenTool' });
  const [modalConfig, setModalConfig] = useState({ isOpen: false, title: "", message: "", type: 'warning' as 'warning' | 'danger', onConfirm: () => { } });

  const fetchServices = async () => {
    try {
      const res = await api.get('/services');
      setServices(res.data);
    } catch (err) { console.error("API Sync Failed"); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchServices(); }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editingId) await api.put(`/services/${editingId}`, formData);
      else await api.post('/services', formData);
      setIsEditorOpen(false);
      fetchServices();
    } catch (err) { alert("Save Failed"); }
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin text-indigo-600" /></div>;

  const designItems = services.filter(s => s.category === 'Design');
  const marketingItems = services.filter(s => s.category === 'Marketing');
  return (
    <div className="p-4 md:p-8 animate-in fade-in duration-500">
      <ConfirmModal {...modalConfig} onCancel={() => setModalConfig({ ...modalConfig, isOpen: false })} />

      <div className="flex justify-between items-center mb-12">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Service Hub</h1>
        <button onClick={() => { setEditingId(null); setFormData({ title: '', category: 'Design', icon: 'PenTool' }); setIsEditorOpen(true); }} className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold transition-transform active:scale-95">+ Add Service</button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        {/* DESIGN SECTION */}
        <div className="space-y-6">
          <div className="flex items-center gap-3 text-indigo-600 font-black uppercase tracking-widest"><Palette /> Design Agency</div>
          <div className="grid grid-cols-1 gap-4">
            {designItems.map((s) => (
              <div key={s._id} className="flex items-center justify-between p-4 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl group shadow-sm">
                <div className="flex items-center gap-4">
                  <div className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 rounded-xl">{IconMap[s.icon] || IconMap['Layout']}</div>
                  <span className="font-bold text-slate-700 dark:text-slate-200">{s.title}</span>
                </div>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditingId(s._id); setFormData(s); setIsEditorOpen(true); }} className="p-2 text-slate-400 hover:text-indigo-600"><Edit size={18} /></button>
                  <button onClick={() => setModalConfig({ isOpen: true, title: "Delete?", message: "Permanently remove service?", type: 'danger', onConfirm: async () => { await api.delete(`/services/${s._id}`); fetchServices(); setModalConfig(m => ({ ...m, isOpen: false })) } })} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={18} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* MARKETING SECTION */}
        <div className="space-y-6">
          <div className="flex items-center gap-3 text-emerald-500 font-black uppercase tracking-widest"><Megaphone /> Digital Marketing</div>
          <div className="grid grid-cols-1 gap-4">
            {marketingItems.map((s) => (
              <div key={s._id} className="flex items-center justify-between p-4 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl group shadow-sm">
                <div className="flex items-center gap-4">
                  <div className="p-2 bg-green-50 dark:bg-green-900/30 text-green-600 rounded-xl">{IconMap[s.icon] || IconMap['Search']}</div>
                  <span className="font-bold text-slate-700 dark:text-slate-200">{s.title}</span>
                </div>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditingId(s._id); setFormData(s); setIsEditorOpen(true); }} className="p-2 text-slate-400 hover:text-indigo-600"><Edit size={18} /></button>
                  <button onClick={() => setModalConfig({ isOpen: true, title: "Delete?", message: "Permanently remove service?", type: 'danger', onConfirm: async () => { await api.delete(`/services/${s._id}`); fetchServices(); setModalConfig(m => ({ ...m, isOpen: false })) } })} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={18} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>
