import { useState, useEffect } from 'react';
import { ShieldCheck, Loader2, CheckCircle2, Mail, Calendar, X, Send, Eye } from 'lucide-react';
import ConfirmModal from '../../Components/Admin/ConfirmModal';
import api from '../../utils/api';

const StudentManager = () => {
  const [enrollments, setEnrollments]   = useState<any[]>([]);
  const [loading, setLoading]           = useState(true);
  const [confirm, setConfirm]           = useState({ isOpen: false, title: '', message: '', onConfirm: () => {} });
  const [receiptPopup, setReceiptPopup] = useState<{
    isOpen: boolean; html: string; enrollmentId: string; isSending: boolean;
  }>({ isOpen: false, html: '', enrollmentId: '', isSending: false });

  const fetchData = async () => {
    try {
      const res = await api.get('/students/enrollments');
      setEnrollments(res.data);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const triggerAction = (title: string, message: string, action: () => Promise<void>) => {
    setConfirm({
      isOpen: true, title, message,
      onConfirm: async () => {
        try {
          await action();
          setConfirm(prev => ({ ...prev, isOpen: false }));
          await fetchData();
        } catch {
          setConfirm(prev => ({ ...prev, isOpen: false }));
        }
      },
    });
  };

  const updateVerificationStatus = async (id: string, status: string) => {
    await api.put(`/students/${id}/verification-status`, { status });
    fetchData();
  };

  const handleReceiptClick = async (id: string) => {
    try {
      const enrollment = enrollments.find(e => e._id === id);
      if (enrollment.paymentInfo.verificationStatus === 'pending') {
        alert('Γ¥î Payment must be VERIFIED before generating receipt.');
        return;
      }
      const res = await api.put(`/students/${id}/receipt-preview`);
      setReceiptPopup({ isOpen: true, html: res.data.receiptHTML, enrollmentId: id, isSending: false });
    } catch (error: any) {
      alert('Γ¥î ' + (error.response?.data?.message || 'Failed to generate receipt'));
    }
  };

  const sendReceiptEmail = async () => {
    try {
      setReceiptPopup(prev => ({ ...prev, isSending: true }));
      await api.put(`/students/${receiptPopup.enrollmentId}/send-receipt`);
      setReceiptPopup({ isOpen: false, html: '', enrollmentId: '', isSending: false });
      fetchData();
      alert('Γ£à Receipt email sent successfully!');
    } catch (error: any) {
      alert('Γ¥î Failed to send receipt: ' + (error.response?.data?.message || error.message));
      setReceiptPopup(prev => ({ ...prev, isSending: false }));
    }
  };

  const updateStatus = async (id: string, status: string) => {
    try {
      await api.put(`/students/${id}/status`, { status });
      await fetchData();
    } catch (error: any) {
      alert(error.response?.data?.message || 'Failed to update status');
    }
  };

  const toggleCertification = async (id: string) => {
    try {
      await api.put(`/students/${id}/issue-cert`);
      fetchData();
    } catch (error: any) {
      alert(error.response?.data?.message || 'Failed to issue certificate');
    }
  };

  const updateDate = async (id: string, date: string) => {
    await api.put(`/students/${id}/issue-date`, { issueDate: date });
    fetchData();
  };

  if (loading) return (
    <div className="h-screen flex items-center justify-center">
      <Loader2 className="animate-spin text-indigo-600" size={48} />
    </div>
  );

  return (
    <div className="p-8 animate-in fade-in duration-500">
      <ConfirmModal
        isOpen={confirm.isOpen}
        title={confirm.title}
        message={confirm.message}
        onConfirm={confirm.onConfirm}
        onCancel={() => setConfirm(prev => ({ ...prev, isOpen: false }))}
      />

      {/* ΓöÇΓöÇ Receipt Preview Popup ΓöÇΓöÇ */}
      {receiptPopup.isOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2rem] w-full max-w-2xl max-h-[92vh] flex flex-col shadow-2xl border border-slate-200 dark:border-slate-700 overflow-hidden">

            {/* Header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 dark:border-slate-800 shrink-0">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
                  <Eye size={16} className="text-indigo-600" />
                </div>
                <div>
                  <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Preview</p>
                  <h3 className="text-sm font-black text-slate-900 dark:text-white">Receipt Email</h3>
                </div>
              </div>
              <button
                onClick={() => setReceiptPopup({ isOpen: false, html: '', enrollmentId: '', isSending: false })}
                className="p-2 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors text-slate-400"
              >
                <X size={18} />
              </button>
            </div>

            {/* Preview */}
            <div className="flex-1 overflow-y-auto p-4 bg-slate-50 dark:bg-slate-950">
              <div className="rounded-xl overflow-hidden shadow-lg">
                <iframe
                  srcDoc={receiptPopup.html}
                  className="w-full border-0"
                  style={{ height: '600px' }}
                  title="Receipt Preview"
                />
              </div>
            </div>

            {/* Footer */}
            <div className="flex items-center justify-between px-6 py-4 border-t border-slate-100 dark:border-slate-800 shrink-0 bg-white dark:bg-slate-900">
              <p className="text-[10px] text-slate-400 font-medium">
                This email will be sent to the student's registered email address.
              </p>
              <div className="flex gap-3">
                <button
                  onClick={() => setReceiptPopup({ isOpen: false, html: '', enrollmentId: '', isSending: false })}
                  disabled={receiptPopup.isSending}
                  className="px-5 py-2.5 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors disabled:opacity-50"
                >
                  Cancel
                </button>
                <button
                  onClick={sendReceiptEmail}
                  disabled={receiptPopup.isSending}
                  className="px-5 py-2.5 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-colors disabled:opacity-60 shadow-lg shadow-emerald-500/20"
                >
                  {receiptPopup.isSending
                    ? <><Loader2 size={14} className="animate-spin" /> SendingΓÇª</>
                    : <><Send size={14} /> Send Email</>
                  }
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-10">Academic Registry</h1>

      <div className="bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-50 dark:bg-slate-800/50 text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-100 dark:border-slate-800">
            <tr>
              <th className="px-6 py-6">Learner Identity</th>
              <th className="px-6 py-6">Payment Proof</th>
              <th className="px-6 py-6">Verification</th>
              <th className="px-6 py-6 text-center">Receipt</th>
              <th className="px-6 py-6">Course Status</th>
              <th className="px-6 py-6">Certification</th>
              <th className="px-6 py-6 text-right">Serial Number</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
            {enrollments.map((item) => {
              const verificationStatus  = item.paymentInfo.verificationStatus;
              const isVerified          = verificationStatus === 'verified';
              const isNotVerified       = verificationStatus === 'not_verified';
              const isPending           = verificationStatus === 'pending';
              const isReceiptSent       = item.receiptSent;
              const courseStatus        = item.status;
              const isCertified         = item.certification.isCertified;
              const hasSerialNumber     = !!item.certification.serialNumber;
              const isReceiptActive     = isNotVerified || isVerified;
              const isCourseStatusActive    = isVerified && isReceiptSent;
              const isCertificationActive   = isCourseStatusActive && courseStatus === 'completed';

              return (
                <tr key={item._id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">

                  {/* 1. Learner Identity */}
                  <td className="px-6 py-6">
                    <p className="text-sm font-black text-slate-900 dark:text-white">{item.personalInfo.fullName}</p>
                    <p className="text-[9px] text-slate-500 font-bold">{item.personalInfo.email}</p>
                    <p className="text-[9px] text-slate-400 font-medium">{item.personalInfo.phone}</p>
                  </td>

                  {/* 2. Payment Proof */}
                  <td className="px-6 py-6">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="px-2 py-1 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 text-[9px] font-black uppercase rounded">
                        {item.paymentInfo.method}
                      </span>
                      <span className="text-[9px] font-mono font-bold text-slate-600 dark:text-slate-400">
                        {item.paymentInfo.transactionId}
                      </span>
                    </div>
                    <a href={item.paymentInfo.screenshotUrl} target="_blank" rel="noopener noreferrer"
                      className="text-[9px] text-blue-500 hover:text-blue-600 font-bold uppercase underline">
                      View Screenshot
                    </a>
                  </td>

                  {/* 3. Verification */}
                  <td className="px-6 py-6">
                    <select
                      value={verificationStatus}
                      onChange={(e) => {
                        const newStatus = e.target.value;
                        if (newStatus !== verificationStatus) {
                          triggerAction(
                            'Change Verification Status?',
                            `Change status to ${newStatus.toUpperCase()}? This will generate a serial number.`,
                            () => updateVerificationStatus(item._id, newStatus)
                          );
                        }
                      }}
                      className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase outline-none cursor-pointer ${
                        isPending   ? 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400' :
                        isVerified  ? 'bg-emerald-500 text-white' :
                                      'bg-red-500 text-white'
                      }`}
                    >
                      <option value="pending">Pending</option>
                      <option value="verified">Verified</option>
                      <option value="not_verified">Not Verified</option>
                    </select>
                  </td>

                  {/* 4. Receipt */}
                  <td className="px-6 py-6 text-center">
                    <button
                      disabled={!isReceiptActive}
                      onClick={() => handleReceiptClick(item._id)}
                      className={`flex items-center justify-center gap-2 px-4 py-2 rounded-xl text-[9px] font-black uppercase w-full transition-all ${
                        !isReceiptActive ? 'opacity-20 cursor-not-allowed bg-slate-100 dark:bg-slate-800 text-slate-400' :
                        isReceiptSent    ? 'bg-emerald-500 text-white hover:bg-emerald-600' :
                                           'bg-black text-white hover:bg-slate-800'
                      }`}
                    >
                      {isReceiptSent
                        ? <><CheckCircle2 size={12} /> Sent</>
                        : <><Mail size={12} /> Send</>
                      }
                    </button>
                  </td>

                  {/* 5. Course Status */}
                  <td className="px-6 py-6">
                    <select
                      disabled={!isCourseStatusActive}
                      value={courseStatus}
                      onChange={(e) => {
                        const val = e.target.value;
                        triggerAction(
                          'Update Course Status?',
                          `Change status to ${val.toUpperCase()}?`,
                          () => updateStatus(item._id, val)
                        );
                      }}
                      className={`px-3 py-2 rounded-xl text-[10px] font-black uppercase outline-none transition-all ${
                        !isCourseStatusActive  ? 'opacity-20 cursor-not-allowed bg-slate-100 dark:bg-slate-800 text-slate-400' :
                        courseStatus === 'completed' ? 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400' :
                        courseStatus === 'ongoing'   ? 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400' :
                                                       'bg-slate-100 dark:bg-slate-800 dark:text-white'
                      }`}
                    >
                      <option value="pending">Pending</option>
                      <option value="ongoing">Ongoing</option>
                      <option value="completed">Completed</option>
                      <option value="cancelled">Cancelled</option>
                    </select>
                  </td>

                  {/* 6. Certification */}
                  <td className="px-6 py-6">
                    <button
                      disabled={!isCertificationActive}
                      onClick={() => triggerAction(
                        isCertified ? 'Revoke Certificate?' : 'Issue Certificate?',
                        isCertified ? 'Revoke this certificate?' : 'Issue certificate to this student?',
                        () => toggleCertification(item._id)
                      )}
                      className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${
                        !isCertificationActive ? 'opacity-20 cursor-not-allowed bg-slate-100 dark:bg-slate-800 text-slate-400' :
                        isCertified            ? 'bg-emerald-500 text-white hover:bg-emerald-600' :
                                                 'bg-indigo-600 text-white hover:bg-indigo-700'
                      }`}
                    >
                      {isCertified
                        ? <><CheckCircle2 size={12} /> Issued</>
                        : <><ShieldCheck size={12} /> Issue</>
                      }
                    </button>
                  </td>

                  {/* 7. Serial + Date */}
                  <td className="px-6 py-6 text-right">
                    {hasSerialNumber ? (
                      <div className="flex flex-col items-end gap-2">
                        <span className="font-mono text-xs font-black text-indigo-600 dark:text-indigo-400">
                          {item.certification.serialNumber}
                        </span>
                        {isCertified ? (
                          <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-800 px-2 py-1 rounded-lg">
                            <Calendar size={12} className="text-slate-400" />
                            <input
                              type="date"
                              className="bg-transparent text-[10px] font-bold outline-none dark:text-white"
                              value={item.certification.issueDate ? new Date(item.certification.issueDate).toISOString().split('T')[0] : ''}
                              onChange={(e) => updateDate(item._id, e.target.value)}
                            />
                          </div>
                        ) : (
                          <span className="text-[9px] text-slate-400 italic">Date: Not Set</span>
                        )}
                      </div>
                    ) : (
                      <span className="text-[10px] text-slate-300 dark:text-slate-600 italic">No Serial</span>
                    )}
                  </td>

                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default StudentManager;

import { useState, useEffect, useRef } from 'react';
import {
  Edit3,
  Trash2,
  Plus,
  Mail,
  Phone,
  X,
  Save,
  Upload,
  Loader2,
} from 'lucide-react';
import ConfirmModal from '../../Components/Admin/ConfirmModal';
import api from '../../utils/api';

const TeamManager = () => {
  const [team, setTeam] = useState<any[]>([]);
  const [stats, setStats] = useState({ total: 0, developers: 0, designers: 0, marketers: 0 });
  const [loading, setLoading] = useState(true);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState({ name: '', role: '', image: '', email: '', phone: '' });
  const [modalConfig, setModalConfig] = useState({ isOpen: false, title: "", message: "", type: 'warning' as 'warning' | 'danger', onConfirm: () => { } });

  const fetchData = async () => {
    try {
      const res = await api.get('/team');
      setTeam(res.data.team);
      setStats(res.data.stats);
    } catch (err) { console.error("Sync Error"); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const uploadData = new FormData();
    uploadData.append('image', file);
    try {
      setUploading(true);
      const res = await api.post('/team/upload', uploadData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setFormData({ ...formData, image: res.data.url });
    } catch (err) { alert("Upload failed."); }
    finally { setUploading(false); }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.image) return alert("Photo required.");
    try {
      if (editingId) await api.put(`/team/${editingId}`, formData);
      else await api.post('/team', formData);
      setIsEditorOpen(false);
      fetchData();
    } catch (err) { alert("Save failed."); }
  };

  if (loading) return <div className="h-screen flex items-center justify-center dark:bg-slate-950"><Loader2 className="animate-spin text-indigo-600" size={40} /></div>;

  return (
    <div className="p-4 md:p-8 animate-in fade-in duration-500">
      <ConfirmModal {...modalConfig} onCancel={() => setModalConfig({ ...modalConfig, isOpen: false })} />

      {/* --- TOP ANALYTICS BAR --- */}
      <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-sm mb-12 flex flex-col md:flex-row divide-y md:divide-y-0 md:divide-x divide-slate-100 dark:divide-slate-800 py-8">
        {[
          { label: 'Team Members', value: stats.total },
          { label: 'Developers', value: stats.developers },
          { label: 'Designers', value: stats.designers },
          { label: 'Marketers', value: stats.marketers },
        ].map((item, i) => (
          <div key={i} className="flex-1 text-center py-4 md:py-0">
            <h2 className="text-4xl font-black text-indigo-600 dark:text-indigo-400 mb-1 tracking-tighter">{item.value}</h2>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{item.label}</p>
          </div>
        ))}
      </div>

      <div className="flex justify-between items-end mb-10">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Personnel</h1>
          <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mt-1">Staff Management Facility</p>
        </div>
        <button onClick={() => { setEditingId(null); setFormData({ name: '', role: '', image: '', email: '', phone: '' }); setIsEditorOpen(true); }} className="bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-8 py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-2xl active:scale-95 transition-all flex items-center gap-2">
          <Plus size={18} /> Register Member
        </button>
      </div>

      {/* --- REFINED TEAM GRID --- */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
        {team.map((member) => (
          <div key={member._id} className="group bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 p-2 pb-6 hover:shadow-2xl transition-all duration-500 overflow-hidden relative">

            {/* Top Image Section */}
            <div className="relative h-64 w-full rounded-[2rem] overflow-hidden mb-6">
              <img src={member.image} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 group-hover:scale-110" alt="" />

              {/* Overlay Actions (Appears on Hover) */}
              <div className="absolute inset-0 bg-slate-950/40 opacity-0 group-hover:opacity-100 transition-all duration-300 backdrop-blur-[2px] flex items-center justify-center gap-3">
                <button onClick={() => { setEditingId(member._id); setFormData(member); setIsEditorOpen(true); }} className="p-4 bg-white text-slate-900 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all transform translate-y-4 group-hover:translate-y-0 shadow-xl">
                  <Edit3 size={20} />
                </button>
                <button onClick={() => setModalConfig({ isOpen: true, title: "Delete?", message: "Purge this profile?", type: 'danger', onConfirm: async () => { await api.delete(`/team/${member._id}`); fetchData(); setModalConfig(m => ({ ...m, isOpen: false })) } })} className="p-4 bg-white text-red-600 rounded-2xl hover:bg-red-600 hover:text-white transition-all transform translate-y-4 group-hover:translate-y-0 shadow-xl delay-75">
                  <Trash2 size={20} />
                </button>
              </div>
            </div>

            {/* Info Section */}
            <div className="px-6 text-center">
              <h3 className="text-xl font-black text-slate-900 dark:text-white tracking-tight line-clamp-1">{member.name}</h3>
              <div className="mt-2 inline-block px-3 py-1 bg-indigo-50 dark:bg-indigo-900/30 rounded-lg">
                <p className="text-[10px] font-black uppercase text-indigo-600 dark:text-indigo-400 tracking-widest">{member.role}</p>
              </div>

              <div className="mt-6 grid grid-cols-2 gap-2 border-t border-slate-50 dark:border-slate-800 pt-6">
                <a href={`mailto:${member.email}`} className="flex flex-col items-center p-3 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                  <Mail size={16} className="text-slate-400 mb-1" />
                  <span className="text-[9px] font-black text-slate-400 uppercase">Email</span>
                </a>
                <a href={`tel:${member.phone}`} className="flex flex-col items-center p-3 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                  <Phone size={16} className="text-slate-400 mb-1" />
                  <span className="text-[9px] font-black text-slate-400 uppercase">Call</span>
                </a>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* --- CENTERED MODAL EDITOR --- */}
      {isEditorOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md transition-opacity" onClick={() => setIsEditorOpen(false)}></div>

          <div className="relative w-full max-w-xl bg-white dark:bg-slate-900 rounded-[3rem] shadow-2xl overflow-hidden border border-slate-200 dark:border-slate-800 animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/50">
              <div>
                <h2 className="text-2xl font-bold dark:text-white">{editingId ? 'Modify Profile' : 'New Registry'}</h2>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Personnel OS</p>
              </div>
              <button onClick={() => setIsEditorOpen(false)} className="p-3 bg-white dark:bg-slate-800 text-slate-400 hover:text-red-500 rounded-full shadow-sm"><X size={24} /></button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              <div className="flex flex-col items-center">
                <div
                  onClick={() => fileInputRef.current?.click()}
                  className="w-32 h-32 rounded-[2.5rem] bg-slate-100 dark:bg-slate-800 border-4 border-dashed border-slate-200 dark:border-slate-700 flex flex-col items-center justify-center cursor-pointer overflow-hidden group transition-all hover:border-indigo-500"
                >
                  {formData.image ? <img src={formData.image} className="w-full h-full object-cover" /> : <Upload className={uploading ? 'animate-bounce text-indigo-500' : 'text-slate-400'} />}
                  <input type="file" ref={fileInputRef} className="hidden" onChange={handleImageUpload} accept="image/*" />
                </div>
                <p className="text-[9px] font-black uppercase text-slate-400 mt-3 tracking-widest">{uploading ? 'UPLOADING...' : 'PUSH TO UPLOAD'}</p>
              </div>

              <div className="space-y-4">
                <div className="group">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-2 mb-1 block">Full Name</label>
                  <input required type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none outline-none dark:text-white font-bold" placeholder="E.g. Nirupom Nixon" />
                </div>
                <div className="group">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-2 mb-1 block">Role</label>
                  <input required type="text" value={formData.role} onChange={e => setFormData({ ...formData, role: e.target.value })} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none outline-none dark:text-white font-bold" placeholder="E.g. Lead Developer" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-2 mb-1 block">Email</label>
                    <input required type="email" value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none outline-none dark:text-white font-bold" placeholder="mail@example.com" />
                  </div>
                  <div>
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-2 mb-1 block">Phone</label>
                    <input required type="text" value={formData.phone} onChange={e => setFormData({ ...formData, phone: e.target.value })} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none outline-none dark:text-white font-bold" placeholder="+880..." />
                  </div>
                </div>
              </div>

              <button type="submit" disabled={uploading} className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black uppercase tracking-[0.2em] shadow-xl shadow-indigo-500/20 active:scale-95 transition-all disabled:opacity-50">
                <Save size={18} className="inline mr-2" /> {editingId ? 'Push Update' : 'Finalize Profile'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TeamManager;

import { useState } from 'react';
import { CheckCircle, Award, Search, GraduationCap, Loader2, AlertCircle } from 'lucide-react';
import axios from 'axios';

const Certification = () => {
  const [serial, setSerial] = useState('');
  const [name, setName] = useState('');
  const [result, setResult] = useState<null | 'success' | 'error'>(null);
  const [loading, setLoading] = useState(false);
  const [verifiedData, setVerifiedData] = useState<any>(null);

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setResult(null);
    setVerifiedData(null);
    
    try {
      const res = await axios.get(`http://localhost:5000/api/students/verify`, {
        params: { serial: serial.trim(), name: name.trim() }
      });
      setVerifiedData(res.data);
      setResult('success');
    } catch (err) { 
      setResult('error'); 
    } finally { 
      setLoading(false); 
    }
  };

  // Safe Date Formatter to prevent crashes
  const formatDate = (dateString: string) => {
    if (!dateString) return "N/A";
    try {
      return new Date(dateString).toLocaleDateString('en-GB', { 
        day: '2-digit', month: 'short', year: 'numeric' 
      });
    } catch (e) {
      return "Invalid Date";
    }
  };

  // --- BULLETPROOF DATA EXTRACTORS ---
  // These prevent the "Object as React Child" crash
  const getCourseName = () => {
    const courseObj = verifiedData?.data?.course || verifiedData?.data?.courseName || verifiedData?.courseTitle;
    if (typeof courseObj === 'object' && courseObj !== null) return courseObj.title;
    return courseObj || "Course";
  };

  const getStudentName = () => {
    const studentObj = verifiedData?.data?.studentName || verifiedData?.data?.name || verifiedData?.studentName;
    if (typeof studentObj === 'object' && studentObj !== null) return studentObj.name;
    return studentObj || "Student";
  };

  return (
    <main className="pt-40 pb-16 bg-white dark:bg-gray-900 min-h-screen">

      <section className="container mx-auto px-4 sm:px-6 lg:px-8 mb-24">
        <div className="flex flex-col lg:flex-row items-center gap-12 lg:gap-20">

          <div className="lg:w-1/2">
            <span className="text-blue-600 dark:text-blue-500 font-extrabold tracking-widest text-sm uppercase mb-4 block">
              Why Certification Matters
            </span>
            <h1 className="text-4xl md:text-5xl font-extrabold text-gray-900 dark:text-white mb-6 leading-tight">
              Validate Your Skills. <br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-indigo-600">Accelerate Your Career.</span>
            </h1>
            <p className="text-gray-600 dark:text-gray-400 text-lg mb-6 leading-relaxed">
              Our certification is more than just a piece of paper. It represents weeks of intensive, project-based learning and mastery of industry-standard tools.
            </p>

            <div className="space-y-4">
              <div className="flex gap-4">
                <div className="bg-green-100 dark:bg-green-900/30 p-2 h-10 w-10 rounded-lg flex items-center justify-center text-green-600 dark:text-green-400">
                  <Award size={20} />
                </div>
                <div>
                  <h3 className="font-bold text-gray-900 dark:text-white">Industry Recognized</h3>
                  <p className="text-sm text-gray-500 dark:text-gray-400">Trusted by top agencies and companies.</p>
                </div>
              </div>
              <div className="flex gap-4">
                <div className="bg-blue-100 dark:bg-blue-900/30 p-2 h-10 w-10 rounded-lg flex items-center justify-center text-blue-600 dark:text-blue-400">
                  <GraduationCap size={20} />
                </div>
                <div>
                  <h3 className="font-bold text-gray-900 dark:text-white">Skill Validation</h3>
                  <p className="text-sm text-gray-500 dark:text-gray-400">Proof of your hands-on expertise.</p>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:w-1/2 relative">
            <div className="absolute inset-0 bg-blue-600 rounded-[2rem] rotate-3 opacity-10"></div>
            <img
              src="https://images.unsplash.com/photo-1523240795612-9a054b0db644?auto=format&fit=crop&q=80&w=2070"
              alt="Graduation"
              className="relative rounded-[2rem] shadow-2xl border-4 border-white dark:border-gray-800"
            />
          </div>
        </div>
      </section>

      <section className="bg-gray-50 dark:bg-gray-800 py-20">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 text-center max-w-3xl">
          
          <h2 className="text-3xl font-bold text-gray-900 dark:text-white mb-4">Verify a Certificate</h2>
          <p className="text-gray-500 dark:text-gray-400 mb-10">
            Enter the student's name and the unique serial number found on the certificate to verify its authenticity.
          </p>

          <form onSubmit={handleVerify} className="bg-white dark:bg-gray-900 p-8 rounded-3xl shadow-xl border border-gray-100 dark:border-gray-700">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
              <div className="text-left">
                <label className="block text-xs font-bold text-gray-700 dark:text-gray-300 mb-2 uppercase">Name</label>
                <input 
                  required 
                  type="text" 
                  value={name} 
                  onChange={e => setName(e.target.value)} 
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 focus:ring-2 focus:ring-blue-500 outline-none dark:text-white" 
                  placeholder="Student Name" 
                />
              </div>
              <div className="text-left">
                <label className="block text-xs font-bold text-gray-700 dark:text-gray-300 mb-2 uppercase">Serial</label>
                <input 
                  required 
                  type="text" 
                  value={serial} 
                  onChange={e => setSerial(e.target.value)} 
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 focus:ring-2 focus:ring-blue-500 outline-none dark:text-white uppercase" 
                  placeholder="GA202607022669" 
                />
              </div>
            </div>
            <button 
              type="submit" 
              disabled={loading} 
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2 transition-colors disabled:opacity-70"
            >
              {loading ? <Loader2 className="animate-spin" /> : "Verify Now"}
            </button>
          </form>

          {/* SUCCESS RESULT UI */}
          {result === 'success' && verifiedData && (
            <div className="mt-8 p-6 bg-green-50 dark:bg-green-900/10 border border-green-200 dark:border-green-800 rounded-2xl animate-in fade-in slide-in-from-bottom-4">
              <div className="flex flex-col items-center justify-center">
                <div className="flex items-center justify-center gap-2 text-green-700 dark:text-green-400 font-bold text-xl mb-4">
                  <CheckCircle size={28} /> Verified Successfully
                </div>
                
                <p className="text-gray-700 dark:text-gray-300 text-lg mb-6">
                  <strong>{getStudentName()}</strong> successfully completed <strong>{getCourseName()}</strong>.
                </p>

                <div className="w-full max-w-sm border-t border-green-200/50 dark:border-green-800/50 pt-4 flex justify-around">
                   <div className="text-center">
                      <p className="text-[10px] font-black uppercase tracking-widest text-gray-500 dark:text-gray-400 mb-1">Issue Date</p>
                      <p className="font-bold text-gray-900 dark:text-white">
                        {formatDate(verifiedData.data?.date || verifiedData.data?.issueDate || verifiedData.issueDate)}
                      </p>
                   </div>
                   <div className="w-px bg-green-200/50 dark:bg-green-800/50"></div>
                   <div className="text-center">
                      <p className="text-[10px] font-black uppercase tracking-widest text-gray-500 dark:text-gray-400 mb-1">Serial Number</p>
                      <p className="font-bold font-mono text-gray-900 dark:text-white uppercase tracking-widest">
                        {verifiedData.data?.serialNumber || verifiedData.serial || serial}
                      </p>
                   </div>
                </div>
              </div>
            </div>
          )}

          {/* ERROR RESULT UI */}
          {result === 'error' && (
            <div className="mt-8 p-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-2xl flex flex-col items-center gap-2 animate-in fade-in zoom-in-95">
              <AlertCircle className="text-red-500 mb-1" size={32} />
              <p className="text-red-600 dark:text-red-400 font-bold text-lg">Certificate not found.</p>
              <p className="text-red-500/80 dark:text-red-400/80 text-sm">Please check the spelling of the name and the exact serial number.</p>
            </div>
          )}
          
        </div>
      </section>

    </main>
  );
};

export default Certification;

