          <h1 className="text-4xl md:text-5xl font-extrabold mb-6 text-gray-900 dark:text-white">
            Meet the <br />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-[#81007F] to-[#4B0081]">Creative Minds</span>
